import json
import tempfile
from typing import Set, List, Optional, Iterable

import numpy as np
from geosat.cloud import PointCloud
from geosat.psanp.abstractions.bundle_classifier import get_bundle_classifier_from_name
from geosat.psanp.abstractions.bundler import Bundle
from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata

from psanp.classifiers.tensorflow.susann_v2_classifier.laz_loader import LazLoader
from psanp.classifiers.tensorflow.susann_v2_classifier.losses import (
    NetworkLoss,
    NetworkMetricIoU,
)
from psanp.classifiers.tensorflow.susann_v2_classifier.network import Network
from psanp.classifiers.tensorflow.susann_v2_classifier.settings import Settings


class SusannV2Classifier(Classifier):
    """A versatile classifier that uses a KDTree, voxels and deep-learning
    to segment point clouds.
    """

    def __init__(
        self,
        save_scores: bool = False,
        save_distances: bool = False,
        stage_name: Optional[str] = None,
    ) -> None:
        super().__init__(stage_name)
        self.save_scores = save_scores
        self.save_distances = save_distances
        if stage_name is None:
            self.config = Settings()
            self.model = Network(self.config)
        else:
            bundle: Bundle = get_bundle_classifier_from_name(self.stage_name)
            self._import_training_data(**bundle["database"])
        self.model.compile(
            "Adam",
            loss=NetworkLoss(self.config),
            metrics=[NetworkMetricIoU(self.config)],
        )

    def _import_training_data(self, model_weights: bytes, config_file: bytes) -> None:
        self.config = Settings(**json.loads(config_file.decode("ascii")))
        self.model = Network(self.config)

        # write model_weight tmp file
        file_object, path = tempfile.mkstemp()
        with open(file_object, "wb") as tmp:
            tmp.write(model_weights)

        self.model.load_weights(path)

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option(
                "save_scores",
                "Should the classification scores be saved in a new LAS field (Default False)",
                type_cast=bool,
                required=False,
            ),
            Option(
                "save_distances",
                "Should the classification distances be saved in a new LAS field (Default False)",
                type_cast=bool,
                required=False,
            ),
        ]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if not cloud:
            return (cloud,)
        if not pipeline_metadata.classification_codes:
            raise KeyError("Missing classification codes inside pipeline_metadata")
        ignored_ids = [
            pipeline_metadata.classification_codes[ignored_class]
            for ignored_class in self.input_classes()
        ]
        selected_indices = np.flatnonzero(~np.isin(cloud.classification, ignored_ids))
        cloud_copy = PointCloud(cloud.coords[selected_indices])
        cloud_copy.add_new_field("classification", dtype=np.uint8)
        dataset = LazLoader(cloud_copy, self.config)

        # Processing dataset
        # TODO: Introduce some sort of parallelism here, to generate the next batch data
        #  while Tensorflow predicts:
        for batch, offsets in dataset:
            predictions = self.model.predict_on_batch(batch)
            dataset.project_batch(
                predictions, offsets[..., 1], offsets[..., 2], offsets[..., 3]
            )

        # Exporting
        dataset.project_to_pointcloud(self.save_scores, self.save_distances)

        # Remapping to user classification codes
        mapping = np.array(
            [
                pipeline_metadata.classification_codes[class_name]
                for class_name in self.config.data.class_names
            ]
        )
        new_classification = mapping[dataset.pointcloud.classification]
        classified_flag = new_classification != 0
        cloud.classification[selected_indices[classified_flag]] = new_classification[
            classified_flag
        ]
        del cloud_copy

        return (cloud,)

    def input_classes(self) -> Set[str]:
        return set(self.config.data.ignore_classes_names)

    def output_classes(self) -> Set[str]:
        return set(self.config.data.class_names)
